defmodule Counter do
  use GenServer

  def start_link(initial), do: GenServer.start_link(__MODULE__, initial, name: __MODULE__)
  def increment, do: GenServer.cast(__MODULE__, :inc)
  def value, do: GenServer.call(__MODULE__, :value)

  @impl true
  def init(state), do: {:ok, state}

  @impl true
  def handle_cast(:inc, state), do: {:noreply, state + 1}

  @impl true
  def handle_call(:value, _from, state), do: {:reply, state, state}
end

defmodule MyApp.Supervisor do
  use Supervisor

  def start_link(_), do: Supervisor.start_link(__MODULE__, :ok, name: __MODULE__)

  @impl true
  def init(:ok) do
    children = [
      {Counter, 0},
      {MyApp.Worker, []}
    ]

    Supervisor.init(children, strategy: :one_for_one)
  end
end

defmodule Fetcher do
  use GenServer

  def start_link(url), do: GenServer.start_link(__MODULE__, url)

  @impl true
  def init(url), do: {:ok, url}

  @impl true
  def handle_call(:fetch, _from, url) do
    # No defensive nil checks: if this fails, the process crashes
    {:ok, body} = HttpClient.get(url)
    {:reply, body, url}
  end
end
# A supervisor restarts Fetcher on crash into a clean state

defmodule Parser do
  @callback parse(String.t()) :: {:ok, term} | {:error, term}
end

defmodule JSONParser do
  @behaviour Parser

  @impl true
  def parse(str), do: {:ok, %{parsed: str}}
end

IO.inspect(JSONParser.parse("{}"))  # {:ok, %{parsed: "{}"}}
